    n2 = n * n
    hex_part = format(n2, 'X')

    def to_base36(num):
        if num == 0:
            return '0'
        digits = []
        while num > 0:
            remainder = num % 36
            if remainder < 10:
                digits.append(str(remainder))
            else:
                digits.append(chr(ord('A') + remainder - 10))
            num = num // 36
        return ''.join(reversed(digits))

    n3 = n * n * n
    tri_base_part = to_base36(n3)
